package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.*;

/**
 * A class that selects a minimal (concise) set of test cases that covers all
 * buggy implementations, using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Uses a greedy set cover algorithm to find a minimal set of test cases
     * from the given TestResults that collectively catch all buggy
     * implementations (files in the wrong set).
     *
     * Does not mutate the input TestResults object or any of its fields.
     *
     * @param results the test results to compute the set cover for
     * @return a set of TestCase objects forming the concise covering set
     */
    public static Set<TestCase> setCover(TestResults results) {
        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<Integer> wrongSet = results.getWrongSet();

        // Working copy of uncovered files
        Set<Integer> uncovered = new HashSet<>(wrongSet);

        // Working copies of coverage sets
        List<Set<Integer>> coverageCopies = new ArrayList<>();
        for (Set<Integer> fileSet : caseToFiles) {
            coverageCopies.add(new HashSet<>(fileSet));
        }

        Set<TestCase> result = new HashSet<>();

        while (!uncovered.isEmpty()) {
            // Find the test case covering the most uncovered files
            int bestIdx = -1;
            int bestCount = 0;

            for (int i = 0; i < coverageCopies.size(); i++) {
                int count = 0;
                for (Integer file : coverageCopies.get(i)) {
                    if (uncovered.contains(file)) {
                        count++;
                    }
                }
                if (count > bestCount) {
                    bestCount = count;
                    bestIdx = i;
                }
            }

            if (bestIdx == -1) {
                break;
            }

            // Add the best test case to the result
            result.add(results.getTestCase(bestIdx));

            // Remove newly covered files from uncovered
            uncovered.removeAll(coverageCopies.get(bestIdx));
        }

        return result;
    }
}

package test.rice.node;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
