import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

class AgentNodeTest {

    // ==================== PyBoolNode Tests ====================

    @Test
    void testBoolGetLeftChildNull() {
        PyBoolNode node = new PyBoolNode();
        assertNull(node.getLeftChild());
    }

    @Test
    void testBoolGetRightChildNull() {
        PyBoolNode node = new PyBoolNode();
        assertNull(node.getRightChild());
    }

    @Test
    void testBoolGenExValsBoth() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(0, 1));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(2, vals.size());
        assertTrue(vals.contains(new PyBoolObj(false)));
        assertTrue(vals.contains(new PyBoolObj(true)));
    }

    @Test
    void testBoolGenExValsFalseOnly() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(0));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyBoolObj(false)));
    }

    @Test
    void testBoolGenExValsTrueOnly() {
        PyBoolNode node = new PyBoolNode();
        node.setExDomain(Arrays.asList(1));
        Set<PyBoolObj> vals = node.genExVals();
        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyBoolObj(true)));
    }

    @Test
    void testBoolGenRandValInDomain() {
        PyBoolNode node = new PyBoolNode();
        node.setRanDomain(Arrays.asList(0, 1));
        for (int i = 0; i < 50; i++) {
            PyBoolObj val = node.genRandVal();
            assertTrue(val.getValue() == true || val.getValue() == false);
        }
    }

    @Test
    void testBoolGenRandValSingleDomain() {
        PyBoolNode node = new PyBoolNode();
        node.setRanDomain(Arrays.asList(1));
        for (int i = 0; i < 20; i++) {
            PyBoolObj val = node.genRandVal();
            assertTrue(val.getValue());
        }
    }

