    @Test
    void testIntGetLeftChildNull() {
        PyIntNode node = new PyIntNode();
        assertNull(node.getLeftChild());
    }

    @Test
    void testIntGetRightChildNull() {
        PyIntNode node = new PyIntNode();
        assertNull(node.getRightChild());
    }

    @Test
    void testIntGenExVals() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(-3, 0, 5));
        Set<PyIntObj> vals = node.genExVals();
        assertEquals(3, vals.size());
        assertTrue(vals.contains(new PyIntObj(-3)));
        assertTrue(vals.contains(new PyIntObj(0)));
        assertTrue(vals.contains(new PyIntObj(5)));
    }

    @Test
