        assertEquals(1, vals.size());
        assertTrue(vals.contains(new PyIntObj(42)));
    }

    @Test
    void testIntGenExValsDuplicates() {
        PyIntNode node = new PyIntNode();
        node.setExDomain(Arrays.asList(1, 1, 2));
        Set<PyIntObj> vals = node.genExVals();
        assertEquals(2, vals.size());
        assertTrue(vals.contains(new PyIntObj(1)));
        assertTrue(vals.contains(new PyIntObj(2)));
    }

    @Test
    void testIntGenRandValInDomain() {
        PyIntNode node = new PyIntNode();
        List<Integer> domain = Arrays.asList(-10, -5, 0, 5, 10);
        node.setRanDomain(domain);
        Set<Integer> domainSet = new HashSet<>(domain);
        for (int i = 0; i < 100; i++) {
            PyIntObj val = node.genRandVal();
