package test.rice.concisegen;

import main.rice.concisegen.ConciseSetGenerator;
import main.rice.obj.APyObj;
import main.rice.obj.PyIntObj;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import org.junit.jupiter.api.Test;

import java.util.*;

import static org.junit.jupiter.api.Assertions.*;

class AgentConciseSetGeneratorTest {

    private TestCase createTestCase(int... args) {
        List<APyObj> objArgs = new ArrayList<>();
        for (int arg : args) {
            objArgs.add(new PyIntObj(arg));
        }
        return new TestCase(objArgs);
    }

    // ==================== Basic coverage tests ====================

    @Test
    void testEmptyWrongSet() {
        List<TestCase> allCases = Arrays.asList(createTestCase(1));
        List<Set<Integer>> caseToFiles = Arrays.asList(new HashSet<>());
        Set<Integer> wrongSet = new HashSet<>();

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertTrue(cover.isEmpty());
    }

    @Test
    void testSingleTestCoversAll() {
        List<TestCase> allCases = Arrays.asList(createTestCase(1));
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1, 2))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }

    @Test
    void testEachTestCoversOneFile() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1)),
            new HashSet<>(Arrays.asList(2))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(3, cover.size());
    }

    @Test
    void testGreedySelectsBest() {
        // Test 0 covers {0, 1, 2}, Test 1 covers {0}, Test 2 covers {1}
        // Greedy should pick Test 0 first and that covers everything
        List<TestCase> allCases = Arrays.asList(
            createTestCase(10),
            createTestCase(20),
            createTestCase(30)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1, 2)),
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(10)));
    }

    @Test
    void testTwoTestsNeeded() {
        // Test 0 covers {0, 1}, Test 1 covers {2, 3}, Test 2 covers {0, 3}
        // Need at least 2; greedy picks test 0 or 1 first (both cover 2),
        // then needs one more
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(2, 3)),
            new HashSet<>(Arrays.asList(0, 3))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2, 3));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(2, cover.size());
        // The cover should catch all wrong files
        Set<Integer> covered = new HashSet<>();
        for (TestCase tc : cover) {
            int idx = allCases.indexOf(tc);
            covered.addAll(caseToFiles.get(idx));
        }
        assertTrue(covered.containsAll(wrongSet));
    }

    @Test
    void testDoesNotMutateWrongSet() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(1))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));
        Set<Integer> originalWrongSet = new HashSet<>(wrongSet);

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        ConciseSetGenerator.setCover(results);

        assertEquals(originalWrongSet, wrongSet);
    }

    @Test
    void testResultCoversAllWrongFiles() {
        // More complex scenario
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3),
            createTestCase(4),
            createTestCase(5)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(1, 2)),
            new HashSet<>(Arrays.asList(2, 3)),
            new HashSet<>(Arrays.asList(3, 4)),
            new HashSet<>(Arrays.asList(0, 4))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1, 2, 3, 4));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);

        // Verify all wrong files are covered
        Set<Integer> covered = new HashSet<>();
        for (TestCase tc : cover) {
            int idx = allCases.indexOf(tc);
            covered.addAll(caseToFiles.get(idx));
        }
        assertTrue(covered.containsAll(wrongSet));
    }

    @Test
    void testSingleWrongFile() {
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>()
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }

    @Test
    void testOverlappingCoverage() {
        // All 3 tests cover file 0; test 0 also covers file 1
        List<TestCase> allCases = Arrays.asList(
            createTestCase(1),
            createTestCase(2),
            createTestCase(3)
        );
        List<Set<Integer>> caseToFiles = Arrays.asList(
            new HashSet<>(Arrays.asList(0, 1)),
            new HashSet<>(Arrays.asList(0)),
            new HashSet<>(Arrays.asList(0))
        );
        Set<Integer> wrongSet = new HashSet<>(Arrays.asList(0, 1));

        TestResults results = new TestResults(allCases, caseToFiles, wrongSet);
        Set<TestCase> cover = ConciseSetGenerator.setCover(results);
        assertEquals(1, cover.size());
        assertTrue(cover.contains(createTestCase(1)));
    }
}
